SELECT name, total_score
FROM contestants
WHERE total_score = (SELECT MAX(total_score) FROM contestants);

SELECT year, voting_region, MIN(score) AS min_score
FROM televoting_scores
GROUP BY year, voting_region;

SELECT contestant_id, total_score
FROM overall_results
WHERE year = 2019;

SELECT AVG(score) AS average_score
FROM jury_scores
WHERE jury_id = 1;

SELECT AVG(score) AS average_jury_score
FROM jury_scores
WHERE year = 2019;

SELECT total_score, ranking
FROM overall_results
WHERE year = 2019;

SELECT name, total_score, song_name, genre, AVG(total_score) OVER () AS avg_total_score
FROM contestants
ORDER BY total_score DESC;
